// COMPLETE, COMPILABLE C code
// Handles multiple test cases as described.
#include <stdio.h>
#include <stdlib.h>
#include <math.h>

#define MAXN 2000
#define PI acos(-1.0)

int cmp_double(const void *a, const void *b) {
    double da = *(const double *)a;
    double db = *(const double *)b;
    if (da < db) return -1;
    if (da > db) return 1;
    return 0;
}

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N;
        scanf("%d", &N);
        int xs[MAXN];
        int ys[MAXN];
        for (int i = 0; i < N; ++i) {
            scanf("%d %d", &xs[i], &ys[i]);
        }
        long long totalTriangles = (long long)N * (N - 1) * (N - 2) / 6;
        long long nonAcute = 0;
        double angles[MAXN * 2];
        for (int i = 0; i < N; ++i) {
            int m = 0;
            for (int j = 0; j < N; ++j) if (j != i) {
                angles[m++] = atan2((double)(ys[j] - ys[i]), (double)(xs[j] - xs[i]));
            }
            qsort(angles, m, sizeof(double), cmp_double);
            for (int k = 0; k < m; ++k) {
                angles[m + k] = angles[k] + 2 * PI;
            }
            long long cnt = 0;
            int p = 0, q = 0;
            for (int a = 0; a < m; ++a) {
                while (p < a + m && angles[p] - angles[a] < PI / 2 - 1e-12) ++p;
                while (q < a + m && angles[q] - angles[a] <= 3 * PI / 2 + 1e-12) ++q;
                cnt += (q - p);
            }
            nonAcute += cnt / 2; // each pair counted twice
        }
        long long acute = totalTriangles - nonAcute;
        printf("%lld\n", acute);
    }
    return 0;
}

