#include <bits/stdc++.h>
using namespace std;
int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T; if(!(cin>>T)) return 0;
    const double PI = acos(-1.0);
    while(T--) {
        int N; cin>>N;
        vector<long long> xs(N), ys(N);
        for(int i=0;i<N;++i) cin>>xs[i]>>ys[i];
        long long total = 1LL*N*(N-1)*(N-2)/6;
        long long nonAcute = 0;
        vector<double> ang;
        ang.reserve(2*N);
        for(int i=0;i<N;++i){
            ang.clear();
            for(int j=0;j<N;++j) if(j!=i){
                ang.push_back(atan2((double)(ys[j]-ys[i]), (double)(xs[j]-xs[i])));
            }
            sort(ang.begin(), ang.end());
            int m = N-1;
            for(int k=0;k<m;++k) ang.push_back(ang[k]+2*PI);
            long long cnt=0;
            int p=0,q=0;
            for(int a=0;a<m;++a){
                while(p<a+m && ang[p]-ang[a] < PI/2 - 1e-12) ++p;
                while(q<a+m && ang[q]-ang[a] <= 3*PI/2 + 1e-12) ++q;
                cnt += (q-p);
            }
            nonAcute += cnt/2;
        }
        cout << (total - nonAcute) << '\n';
    }
    return 0;
}
